[CmdletBinding()]
param(
 [string]$ManifestPath='outputs\THREE_LANE_REVERSION_STRONG_SIGNAL_LOT_CAP_HOLDOUT_MODEL1_MANIFEST.csv',[string]$ReportDir='outputs\three_lane_reversion_strong_signal_lot_cap_holdout_model1_package\reports_here',[string]$CompileAuditPath='outputs\THREE_LANE_REVERSION_STRONG_SIGNAL_LOT_CAP_COMPILE_AUDIT.csv',[string]$ResultsPath='outputs\THREE_LANE_REVERSION_STRONG_SIGNAL_LOT_CAP_HOLDOUT_MODEL1_RESULTS.csv',[string]$SummaryPath='outputs\THREE_LANE_REVERSION_STRONG_SIGNAL_LOT_CAP_HOLDOUT_MODEL1_SUMMARY.csv',[string]$DecisionCsvPath='outputs\THREE_LANE_REVERSION_STRONG_SIGNAL_LOT_CAP_HOLDOUT_DECISION.csv',[string]$DecisionMarkdownPath='outputs\THREE_LANE_REVERSION_STRONG_SIGNAL_LOT_CAP_HOLDOUT_DECISION.md',[string]$RunAttestationPath='outputs\THREE_LANE_REVERSION_STRONG_SIGNAL_LOT_CAP_HOLDOUT_MODEL1_RUN_ATTESTATION.csv'
)
$ErrorActionPreference='Stop';Set-StrictMode -Version Latest
$repo=(Resolve-Path (Join-Path $PSScriptRoot '..')).Path;$sourceHash='C28534F328F3775AC825E5A8C53B1A66BD2745662B7AAC7B4CACBB76B31D1F91';$controlName='sslc_control';$centerName='sslc_center015';$continuous='continuous_2021_2026';$windows=@('holdout_2021_2022','holdout_2023_2024','holdout_2025_2026',$continuous)
function Resolve-P([string]$p){if([IO.Path]::IsPathRooted($p)){return $p};return Join-Path $repo $p};function Money([double]$v){$s=if($v-ge 0){'+'}else{'-'};return $s+'$'+[Math]::Abs($v).ToString('N2',[Globalization.CultureInfo]::InvariantCulture)};function B([bool]$v){if($v){'PASS'}else{'FAIL'}}
$manifest=@(Import-Csv (Resolve-P $ManifestPath));$audit=Import-Csv (Resolve-P $CompileAuditPath);if($manifest.Count-ne 8){throw 'Expected eight holdout rows.'};if($audit.Status-ne'COMPILE_PASS'-or$audit.SourceSha256-ne$sourceHash-or$audit.CompileErrors-ne'0'-or$audit.CompileWarnings-ne'0'){throw 'Compile audit invalid.'};$binary=[string]$audit.PortableBinarySha256
foreach($m in $manifest){if($m.SourceSha256-ne$sourceHash-or[int]$m.Model-ne 1){throw 'Manifest identity changed.'};$c=Resolve-P([string]$m.PackageConfig);if((Get-FileHash $c -Algorithm SHA256).Hash-ne$m.ConfigSha256){throw "Config changed at $($m.QueueRank)"}}
$rr='work\SSLC_H_RAW_RESULTS.csv';$rs='work\SSLC_H_RAW_SUMMARY.csv';$rm='work\SSLC_H_RAW_METRICS.md';& powershell.exe -NoProfile -ExecutionPolicy Bypass -File (Join-Path $PSScriptRoot 'collect_validation_results.ps1') -RepoRoot $repo -ManifestPath $ManifestPath -ReportDir $ReportDir -ReportNameTemplate '{ExpectedReportName}' -OutResults $rr -OutSummary $rs -OutMarkdown $rm|Out-Null;if($LASTEXITCODE-ne 0){throw 'Collector failed.'};$raw=@(Import-Csv (Resolve-P $rr));if($raw.Count-ne 8-or@($raw|Where-Object{$_.Status-ne'PARSED'}).Count){throw 'Expected eight parsed reports.'};$rawBy=@{};foreach($x in $raw){$rawBy[[string]$x.ExpectedReportName]=$x}
$workers=[Collections.Generic.List[object]]::new();foreach($pat in @('THREE_LANE_REVERSION_STRONG_SIGNAL_LOT_CAP_HOLDOUT_MODEL1_EXACT_?.csv','THREE_LANE_REVERSION_STRONG_SIGNAL_LOT_CAP_HOLDOUT_MODEL1_RETRY_?.csv')){foreach($f in Get-ChildItem (Join-Path $repo 'outputs') -Filter $pat -File){foreach($x in @(Import-Csv $f.FullName)){$workers.Add($x)|Out-Null}}};if($workers.Count-lt 8-or@($workers|Where-Object{$_.PackageSourceSha256-ne$sourceHash-or$_.PortableExpertRecompiled-ne'False'-or($_.Status-eq'REPORT_FOUND'-and$_.PortableBinarySha256-ne$binary)}).Count){throw 'Runner identity invalid.'}
$validBy=@{};foreach($rank in 1..8){$a=@($workers|Where-Object{[int]$_.QueueRank-eq$rank});$v=@($a|Where-Object{$_.Status-eq'REPORT_FOUND'});if($v.Count-ne 1){throw "Rank $rank valid count $($v.Count)"};$validBy[[string]$rank]=$v[0]}
$results=[Collections.Generic.List[object]]::new();$att=[Collections.Generic.List[object]]::new()
foreach($m in $manifest|Sort-Object{[int]$_.QueueRank}){$p=$rawBy[[string]$m.ExpectedReportName];$run=$validBy[[string]$m.QueueRank];$id=Get-Content ([string]$run.ReportIdentityPath) -Raw|ConvertFrom-Json;if($id.SourceSha256-ne$sourceHash-or$id.PortableBinarySha256-ne$binary-or$id.ReportSha256-ne$run.ReportSha256-or$id.ConfigSha256-ne$run.PackageConfigSha256){throw "Sidecar mismatch $($m.QueueRank)"};$rdd=if([double]$p.MaxDrawdownPercent-gt 0){[double]$p.TotalReturnPercent/[double]$p.MaxDrawdownPercent}else{0};$results.Add([pscustomobject][ordered]@{QueueRank=[int]$m.QueueRank;Candidate=$m.Candidate;Role=$m.Role;Window=$m.Window;From=$m.From;To=$m.To;Model=1;ProfileSha256=$m.ProfileSha256;SourceSha256=$sourceHash;BinarySha256=$binary;NetProfit=[math]::Round([double]$p.NetProfit,2);TotalReturnPercent=[math]::Round([double]$p.TotalReturnPercent,2);CagrPercent=[math]::Round([double]$p.CagrPercent,2);ProfitFactor=[math]::Round([double]$p.ProfitFactor,2);TotalTrades=[int]$p.TotalTrades;WinRatePercent=[math]::Round([double]$p.WinRatePercent,2);MaxDrawdownPercent=[math]::Round([double]$p.MaxDrawdownPercent,2);RecoveryFactor=[math]::Round([double]$p.RecoveryFactor,4);ReturnDrawdown=[math]::Round($rdd,4);MaxConsecutiveLosses=[int]$p.MaxConsecutiveLosses;ReportSha256=$run.ReportSha256})|Out-Null;$attempts=@($workers|Where-Object{[int]$_.QueueRank-eq[int]$m.QueueRank});$att.Add([pscustomobject][ordered]@{QueueRank=[int]$m.QueueRank;Candidate=$m.Candidate;Window=$m.Window;Status=$run.Status;Attempts=$attempts.Count;IdentityRetries=@($attempts|Where-Object{$_.Status-eq'ERROR'}).Count;SourceSha256=$run.PackageSourceSha256;BinarySha256=$run.PortableBinarySha256;ConfigSha256=$run.PackageConfigSha256;ReportSha256=$run.ReportSha256;IdentitySidecarPresent=$true;PortableExpertRecompiled=$false;Started=$run.Started;Finished=$run.Finished})|Out-Null}
$results|Export-Csv (Resolve-P $ResultsPath)-NoTypeInformation -Encoding ASCII;$att|Export-Csv (Resolve-P $RunAttestationPath)-NoTypeInformation -Encoding ASCII;$by=@{};foreach($x in $results){$by["$($x.Candidate)|$($x.Window)"]=$x};$control=$by["$controlName|$continuous"];$center=$by["$centerName|$continuous"]
$allCenterPositive=@($results|Where-Object{$_.Candidate-eq$centerName-and[double]$_.NetProfit-le 0}).Count-eq 0;$noWorse=$true;foreach($w in $windows){if([double]$by["$centerName|$w"].NetProfit-lt[double]$by["$controlName|$w"].NetProfit){$noWorse=$false}};$growth=[double]$center.NetProfit-ge 1.05*[double]$control.NetProfit;$cagr=[double]$center.CagrPercent-ge[double]$control.CagrPercent+0.08;$eff=[double]$center.ProfitFactor-ge[double]$control.ProfitFactor-and[double]$center.RecoveryFactor-ge[double]$control.RecoveryFactor-and[double]$center.ReturnDrawdown-ge[double]$control.ReturnDrawdown;$risk=[double]$center.MaxDrawdownPercent-le 1.35-and[double]$center.MaxDrawdownPercent-le[double]$control.MaxDrawdownPercent+0.10;$trades=[int]$center.TotalTrades-ge[int]$control.TotalTrades-2;$passed=$allCenterPositive-and$noWorse-and$growth-and$cagr-and$eff-and$risk-and$trades
$summary=foreach($name in @($controlName,$centerName)){$c=$by["$name|$continuous"];[pscustomobject][ordered]@{Candidate=$name;Role=$c.Role;Net2021_2022=$by["$name|holdout_2021_2022"].NetProfit;Net2023_2024=$by["$name|holdout_2023_2024"].NetProfit;Net2025_2026=$by["$name|holdout_2025_2026"].NetProfit;ContinuousNetProfit=$c.NetProfit;TotalReturnPercent=$c.TotalReturnPercent;CagrPercent=$c.CagrPercent;ProfitFactor=$c.ProfitFactor;TotalTrades=$c.TotalTrades;MaxDrawdownPercent=$c.MaxDrawdownPercent;RecoveryFactor=$c.RecoveryFactor;ReturnDrawdown=$c.ReturnDrawdown}}
$summary|Export-Csv (Resolve-P $SummaryPath)-NoTypeInformation -Encoding ASCII;$d=[pscustomobject][ordered]@{Status=if($passed){'HOLDOUT_GATE_PASSED'}else{'REJECTED_IN_HOLDOUT'};ReportsParsed=$results.Count;IdentityValidReports=$att.Count;TotalAttempts=$workers.Count;IdentityRefusals=@($workers|Where-Object{$_.Status-eq'ERROR'}).Count;AllCenterWindowsPositive=$allCenterPositive;CenterNoWorseEveryWindow=$noWorse;CenterGrowthGate=$growth;CenterCagrGate=$cagr;CenterEfficiencyGate=$eff;CenterRiskGate=$risk;CenterTradeCountGate=$trades;Model4ValidationPermitted=$passed;ResearchPromotionPermitted=$false;ForwardCandidateChanged=$false;RealAccountTradingAllowed=$false;ControlNetProfit=$control.NetProfit;CenterNetProfit=$center.NetProfit;SourceSha256=$sourceHash;BinarySha256=$binary;CenterProfileSha256=$center.ProfileSha256};$d|Export-Csv (Resolve-P $DecisionCsvPath)-NoTypeInformation -Encoding ASCII
$lines=[Collections.Generic.List[string]]::new();$lines.Add('# Strong-Signal Selective Lot-Cap Recent-Data Decision');$lines.Add('');$lines.Add($(if($passed){'**Decision: RECENT-DATA GATE PASSED. Exact Model 4 comparison may be frozen; promotion remains closed.**'}else{'**Decision: REJECTED IN RECENT-DATA VALIDATION. Model 4, promotion, forward change, and live approval remain closed.**'}));$lines.Add('');$lines.Add("- Reports: ``$($results.Count) / 8``; attempts: ``$($workers.Count)``; refusals: ``$(@($workers|Where-Object{$_.Status-eq'ERROR'}).Count)``");$lines.Add("- Source: ``$sourceHash``; EX5: ``$binary``");$lines.Add('- These years are feature-level validation, not globally untouched market data.');$lines.Add('');$lines.Add('| Profile | 2021-22 | 2023-24 | 2025-26 | Continuous | CAGR | PF | Trades | DD | Recovery | Return/DD |');$lines.Add('|---|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|');foreach($x in $summary){$label=if($x.Candidate-eq$centerName){'**Selective center**'}else{'Control'};$lines.Add("| $label | $(Money([double]$x.Net2021_2022)) | $(Money([double]$x.Net2023_2024)) | $(Money([double]$x.Net2025_2026)) | $(Money([double]$x.ContinuousNetProfit)) | $($x.CagrPercent)%/yr | $($x.ProfitFactor) | $($x.TotalTrades) | $($x.MaxDrawdownPercent)% | $($x.RecoveryFactor) | $($x.ReturnDrawdown) |")};$lines.Add('');$lines.Add('## Frozen Gate');$lines.Add('');$lines.Add("- Center positive/no worse every window: ``$allCenterPositive / $noWorse`` ($(B($allCenterPositive-and$noWorse)))");$lines.Add("- Growth/CAGR: ``$growth / $cagr`` ($(B($growth-and$cagr)))");$lines.Add("- PF/recovery/return-DD: ``$eff`` ($(B $eff))");$lines.Add("- Drawdown/trades: ``$risk / $trades`` ($(B($risk-and$trades)))");$lines.Add('');$lines.Add($(if($passed){'Only the exact center may proceed to a separately frozen Model 4 real-tick comparison. This is not promotion.'}else{'No threshold or cap rescue is permitted; Model 4 stays sealed.'}));$lines.Add('');$lines.Add('ATB150 and the forward candidate remain unchanged; real trading remains disabled.');$lines|Set-Content (Resolve-P $DecisionMarkdownPath)-Encoding ASCII
Remove-Item (Resolve-P $rr),(Resolve-P $rs),(Resolve-P $rm)-Force -ErrorAction SilentlyContinue;$d
